import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    best_time_penalty = float('inf')

    for i, node in enumerate(unvisited_customers):
        distance_to_node = np.linalg.norm(cur_truck_pos - node)
        travel_time = distance_to_node / truck_speed
        arrival_time = current_time + travel_time

        if arrival_time <= time_windows[i][1]:
            if arrival_time >= time_windows[i][0]:
                time_penalty = 0
            else:
                time_penalty = time_windows[i][0] - arrival_time
        else:
            time_penalty = arrival_time - time_windows[i][1]

        if time_penalty < best_time_penalty:
            best_time_penalty = time_penalty
            best_node = i

    return best_node
